package org.eclipse.rdf4j.benchmark.plan;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.concurrent.TimeUnit;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class ThemeQueryBenchmarkResultsScriptTest {

	@TempDir
	Path tempDir;

	@Test
	void captureSynthesizesSummaryRowsForThemeQueryHexaBenchmark() throws Exception {
		Path rawResult = tempDir.resolve("raw-jmh.txt");
		Path output = tempDir.resolve("results-2026-06-03.md");
		Files.writeString(
				rawResult,
				"""
						# Parameters: (themeName = PHARMA, z_queryIndex = 10)
						Result "org.eclipse.rdf4j.sail.lmdb.benchmark.ThemeQueryHexaBenchmark.executeQuery":
						20.000 ms/op
						""",
				StandardCharsets.UTF_8);

		Process process = new ProcessBuilder("bash", scriptPath().toString(), "capture", "--output",
				output.toString(), rawResult.toString())
						.redirectErrorStream(true)
						.start();

		assertTrue(process.waitFor(10, TimeUnit.SECONDS), "capture script did not finish");
		String processOutput = new String(process.getInputStream().readAllBytes(), StandardCharsets.UTF_8);

		assertEquals(0, process.exitValue(), processOutput);
		String markdown = Files.readString(output, StandardCharsets.UTF_8);
		assertTrue(markdown.contains("ThemeQueryHexaBenchmark.executeQuery"), markdown);
		assertTrue(markdown.contains("PHARMA"), markdown);
		assertTrue(markdown.contains("10"), markdown);
		assertTrue(markdown.contains("20.000"), markdown);
	}

	private static Path scriptPath() {
		return Path.of("..", "..", "core", "sail", "lmdb", "src", "test", "java", "org", "eclipse", "rdf4j",
				"sail", "lmdb", "benchmark", "theme-query-benchmark-results", "theme-query-benchmark-results.sh")
				.toAbsolutePath()
				.normalize();
	}
}
